function check_reinitializationReverts(address owner1, address op1, address owner2, address op2) public {
    // First initialization
    tokenRoles.__TokenRoles_init(owner1, op1);

    // Second initialization should revert
    try tokenRoles.__TokenRoles_init(owner2, op2) {
        assert(false); // Should not reach here
    } catch {
        // Expected to revert
    }
}
